parameters.jsCode:
// Extract server list for client API calls
const servers = ($json.data || []).map(s => ({
  json: {
    id: s.attributes.id,
    identifier: s.attributes.identifier,
    name: s.attributes.name,
    node: s.attributes.node,
    description: s.attributes.description || ''
  }
}));
return servers;

const staticData = this.getWorkflowStaticData('global');
staticData.lastState ??= {};
staticData.alertsSent ??= {};

const loopItem = $('Loop Servers').first().json;
const serverId = loopItem.identifier;
const serverName = loopItem.name;

const state = $json?.attributes?.current_state ?? 'unknown';
const resources = $json?.attributes?.resources || {};
const limits = $json?.attributes?.limits || {};

const lastState = staticData.lastState[serverId] || 'unknown';
const stateChanged = state !== lastState;
staticData.lastState[serverId] = state;

// Detect issues
const issues = [];
const memPct = limits.memory > 0 ? (resources.memory_bytes / (limits.memory * 1024 * 1024)) * 100 : 0;
const cpuPct = resources.cpu_absolute || 0;

if (state === 'offline' && lastState === 'running') issues.push('went OFFLINE');
if (state === 'stopping' && lastState === 'running') issues.push('is STOPPING unexpectedly');
if (memPct > 90) issues.push(`HIGH MEMORY: ${memPct.toFixed(0)}%`);
if (cpuPct > 95) issues.push(`HIGH CPU: ${cpuPct.toFixed(0)}%`);

// Only alert once per issue per 30 min
const now = Date.now();
const alertKey = `${serverId}_${state}`;
const lastAlert = staticData.alertsSent[alertKey] || 0;
const shouldAlert = issues.length > 0 && stateChanged && (now - lastAlert > 1800000);

if (shouldAlert) staticData.alertsSent[alertKey] = now;

return [{
  json: {
    serverId, serverName, state, lastState, stateChanged,
    memPct: memPct.toFixed(1),
    cpuPct: cpuPct.toFixed(1),
    diskMB: ((resources.disk_bytes || 0) / 1048576).toFixed(0),
    issues,
    shouldAlert
  }
}];

